SELECT id, metric_id, `year`, `month`, dimension_type, dimension_value,
       product_title, actual, jbp_goal
FROM metric_breakdown_data
WHERE metric_id = #{metricId}
  AND `year` = #{year}
  AND `month` = #{month}
  AND dimension_type = #{dimensionType}

